package versioned

import (
	"fmt"

	runtimev1alpha1 "github.com/volcano-sh/agent/client-go/clientset/versioned/typed/runtime/v1alpha1"
	discovery "k8s.io/client-go/discovery"
	rest "k8s.io/client-go/rest"
	flowcontrol "k8s.io/client-go/util/flowcontrol"
)

type Interface interface {
	Discovery() discovery.DiscoveryInterface
	RuntimeV1alpha1() runtimev1alpha1.RuntimeV1alpha1Interface
}

type Clientset struct {
	*discovery.DiscoveryClient
	runtimeV1alpha1 *runtimev1alpha1.RuntimeV1alpha1Client
}

func (c *Clientset) RuntimeV1alpha1() runtimev1alpha1.RuntimeV1alpha1Interface {
	return c.runtimeV1alpha1
}

func (c *Clientset) Discovery() discovery.DiscoveryInterface {
	if c == nil {
		return nil
	}
	return c.DiscoveryClient
}

func NewForConfig(c *rest.Config) (*Clientset, error) {
	configShallowCopy := *c
	if configShallowCopy.RateLimiter == nil && configShallowCopy.QPS > 0 {
		if configShallowCopy.Burst <= 0 {
			return nil, fmt.Errorf("burst is required to be greater than 0 when QPS is set to greater than 0")
		}
		configShallowCopy.RateLimiter = flowcontrol.NewTokenBucketRateLimiter(configShallowCopy.QPS, configShallowCopy.Burst)
	}
	var cs Clientset
	var err error
	cs.runtimeV1alpha1, err = runtimev1alpha1.NewForConfig(&configShallowCopy)
	if err != nil {
		return nil, err
	}
	cs.DiscoveryClient, err = discovery.NewDiscoveryClientForConfig(&configShallowCopy)
	if err != nil {
		return nil, err
	}
	return &cs, nil
}

func NewForConfigOrDie(c *rest.Config) *Clientset {
	var cs Clientset
	cs.runtimeV1alpha1 = runtimev1alpha1.NewForConfigOrDie(c)
	cs.DiscoveryClient = discovery.NewDiscoveryClientForConfigOrDie(c)
	return &cs
}

func New(c rest.Interface) *Clientset {
	var cs Clientset
	cs.runtimeV1alpha1 = runtimev1alpha1.New(c)
	cs.DiscoveryClient = discovery.NewDiscoveryClient(c)
	return &cs
}

