	}

	CodeInterpreterGVR = schema.GroupVersionResource{
		Group:    "runtime.agentcube.volcano.sh",
		Version:  "v1alpha1",
		Resource: "codeinterpreters",
	}
)

type K8sClient struct {
	config     *rest.Config
	clientset  kubernetes.Interface
	dynamicCli dynamic.Interface
	namespace  string
}

func NewK8sClient(kubeconfig, masterURL string) (*K8sClient, error) {
	config, err := buildConfig(kubeconfig, masterURL)
	if err != nil {
		return nil, fmt.Errorf("failed to build config: %w", err)
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create clientset: %w", err)
	}

	dynamicCli, err := dynamic.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create dynamic client: %w", err)
	}

	return &K8sClient{
		config:     config,
		clientset:  clientset,
		dynamicCli: dynamicCli,
		namespace:  "default",
	}, nil
}

func buildConfig(kubeconfig, masterURL string) (*rest.Config, error) {
	if kubeconfig != "" {
		return clientcmd.BuildConfigFromFlags(masterURL, kubeconfig)
	}
	return rest.InClusterConfig()
}

func (c *K8sClient) Start(ctx context.Context) error {
	_, err := c.clientset.Discovery().ServerVersion()
	if err != nil {
		return fmt.Errorf("failed to connect to Kubernetes API: %w", err)
	}
	klog.InfoS("Successfully connected to Kubernetes API")
	return nil
}

func (c *K8sClient) GetAgentRuntime(ctx context.Context, namespace, name string) (map[string]interface{}, error) {
	return c.dynamicCli.Resource(AgentRuntimeGVR).Namespace(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *K8sClient) GetCodeInterpreter(ctx context.Context, namespace, name string) (map[string]interface{}, error) {
	return c.dynamicCli.Resource(CodeInterpreterGVR).Namespace(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *K8sClient) CreateSandbox(ctx context.Context, namespace string, obj map[string]interface{}) (map[string]interface{}, error) {
	return c.dynamicCli.Resource(SandboxGVR).Namespace(namespace).Create(ctx, obj, metav1.CreateOptions{})
}

func (c *K8sClient) GetSandbox(ctx context.Context, namespace, name string) (map[string]interface{}, error) {
	return c.dynamicCli.Resource(SandboxGVR).Namespace(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *K8sClient) DeleteSandbox(ctx context.Context, namespace, name string) error {
