			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	resp := &types.CreateSandboxResponse{
		SessionID:   sandboxInfo.SessionID,
		SandboxID:   sandboxInfo.SandboxID,
		SandboxName: sandboxInfo.Name,
		EntryPoints: sandboxInfo.EntryPoints,
	}

	c.JSON(http.StatusOK, resp)
}

func (s *Server) handleDeleteSandbox(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "session id is required"})
		return
	}

	ctx := c.Request.Context()

	if err := s.deleteSandboxBySessionID(ctx, sessionID); err != nil {
		klog.ErrorS(err, "Failed to delete sandbox", "sessionID", sessionID)
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"status":    "deleted",
		"sessionId": sessionID,
	})
}

func (s *Server) deleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	sandbox, err := s.k8sClient.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		return fmt.Errorf("failed to get sandbox: %w", err)
	}

	if sandbox == nil {
		return nil
	}

	return s.k8sClient.DeleteSandbox(ctx, sandbox.Namespace, sandbox.Name)
}

