	if apiErr, ok := err.(api.APIStatus); ok {
		c.JSON(int(apiErr.Status().Code), gin.H{
			"error":  apiErr.Status().Message,
			"reason": apiErr.Status().Reason,
		})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
}

