		Resource: "agentruntimes",
	}

	CodeInterpreterGVR = schema.GroupVersionResource{
		Group:    "runtime.agentcube.volcano.sh",
		Version:  "v1alpha1",
		Resource: "codeinterpreters",
	}
)

type K8sClient struct {
	config     *rest.Config
	clientset  kubernetes.Interface
	dynamicCli dynamic.Interface
	namespace  string
}

func NewK8sClient(kubeconfig, masterURL string) (*K8sClient, error) {
	config, err := buildConfig(kubeconfig, masterURL)
	if err != nil {
		return nil, fmt.Errorf("failed to build config: %w", err)
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create clientset: %w", err)
	}

	dynamicCli, err := dynamic.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create dynamic client: %w", err)
	}

	return &K8sClient{
		config:     config,
		clientset:  clientset,
		dynamicCli: dynamicCli,
		namespace:  "default",
	}, nil
}

func buildConfig(kubeconfig, masterURL string) (*rest.Config, error) {
	if kubeconfig != "" {
		return clientcmd.BuildConfigFromFlags(masterURL, kubeconfig)
	}
	return rest.InClusterConfig()
}

func (c *K8sClient) Start(ctx context.Context) error {
	_, err := c.clientset.Discovery().ServerVersion()
	if err != nil {
		return fmt.Errorf("failed to connect to Kubernetes API: %w", err)
	}
	klog.InfoS("Successfully connected to Kubernetes API")
	return nil
}

func (c *K8sClient) GetAgentRuntime(ctx context.Context, namespace, name string) (*unstructured.Unstructured, error) {
	return c.dynamicCli.Resource(AgentRuntimeGVR).Namespace(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *K8sClient) GetCodeInterpreter(ctx context.Context, namespace, name string) (*unstructured.Unstructured, error) {
	return c.dynamicCli.Resource(CodeInterpreterGVR).Namespace(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *K8sClient) CreateSandbox(ctx context.Context, namespace string, obj *unstructured.Unstructured) (*unstructured.Unstructured, error) {
	return c.dynamicCli.Resource(SandboxGVR).Namespace(namespace).Create(ctx, obj, metav1.CreateOptions{})
}

func (c *K8sClient) GetSandbox(ctx context.Context, namespace, name string) (*unstructured.Unstructured, error) {
	return c.dynamicCli.Resource(SandboxGVR).Namespace(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *K8sClient) DeleteSandbox(ctx context.Context, namespace, name string) error {
	return c.dynamicCli.Resource(SandboxGVR).Namespace(namespace).Delete(ctx, name, metav1.DeleteOptions{})
}

func (c *K8sClient) ListSandboxesByLabel(ctx context.Context, namespace, labelSelector string) ([]map[string]interface{}, error) {
	list, err := c.dynamicCli.Resource(SandboxGVR).Namespace(namespace).List(ctx, metav1.ListOptions{
		LabelSelector: labelSelector,
	})
	if err != nil {
		return nil, err
	}

	items := make([]map[string]interface{}, 0, len(list.Items))
	for _, item := range list.Items {
		items = append(items, item.Object)
	}
	return items, nil
}

func (c *K8sClient) GetSandboxBySessionID(ctx context.Context, sessionID string) (map[string]interface{}, error) {
	labelSelector := fmt.Sprintf("%s=%s", SessionIdLabelKey, sessionID)
	list, err := c.dynamicCli.Resource(SandboxGVR).List(ctx, metav1.ListOptions{
		LabelSelector: labelSelector,
	})
	if err != nil {
		return nil, err
	}

	if len(list.Items) == 0 {
		return nil, nil
	}

	return list.Items[0].Object, nil
}

func (c *K8sClient) ListExpiredSandboxes(ctx context.Context, before time.Time) ([]map[string]interface{}, error) {
	annotationSelector := fields.OneTermEqualSelector(metav1.ObjectNameField, "").String()
	list, err := c.dynamicCli.Resource(SandboxGVR).List(ctx, metav1.ListOptions{
		FieldSelector: annotationSelector,
	})
	if err != nil {
		return nil, err
	}

	items := make([]map[string]interface{}, 0)
	for _, item := range list.Items {
		annotations := item.GetAnnotations()
		if annotations == nil {
			continue
		}
		expiresAtStr, ok := annotations[ExpiresAtAnnotationKey]
		if !ok {
			continue
		}
		expiresAt, err := time.Parse(time.RFC3339, expiresAtStr)
		if err != nil {
			continue
		}
		if expiresAt.Before(before) {
			items = append(items, item.Object)
		}
	}
	return items, nil
}

func (c *K8sClient) CreateSecret(ctx context.Context, namespace string, obj *unstructured.Unstructured) (*unstructured.Unstructured, error) {
	return c.dynamicCli.Resource(schema.GroupVersionResource{
		Group:    "",
		Version:  "v1",
		Resource: "secrets",
	}).Namespace(namespace).Create(ctx, obj, metav1.CreateOptions{})
}

func (c *K8sClient) GetSecret(ctx context.Context, namespace, name string) (*unstructured.Unstructured, error) {
	return c.dynamicCli.Resource(schema.GroupVersionResource{
		Group:    "",
		Version:  "v1",
		Resource: "secrets",
	}).Namespace(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *K8sClient) ValidateToken(ctx context.Context, token string) (string, error) {
	review := map[string]interface{}{
		"apiVersion": "authentication.k8s.io/v1",
		"kind":       "TokenReview",
		"spec": map[string]interface{}{
			"token": token,
		},
	}

	result, err := c.clientset.Discovery().RESTClient().Post().
		AbsPath("/apis/authentication.k8s.io/v1/tokenreviews").
		Body(review).
		DoRaw(ctx)
	if err != nil {
		return "", fmt.Errorf("token review failed: %w", err)
	}

	klog.V(4).InfoS("Token review result", "result", string(result))
	return string(result), nil
}

