package workloadmanager

import (
	"context"
	"time"

	"k8s.io/klog/v2"
)

type GarbageCollector struct {
	k8sClient *K8sClient
	interval  time.Duration
	stopCh    chan struct{}
}

func NewGarbageCollector(k8sClient *K8sClient, interval time.Duration) *GarbageCollector {
	if interval <= 0 {
		interval = 15 * time.Second
	}
	return &GarbageCollector{
		k8sClient: k8sClient,
		interval:  interval,
		stopCh:    make(chan struct{}),
	}
}

func (gc *GarbageCollector) Start(ctx context.Context) {
	klog.InfoS("Starting garbage collector", "interval", gc.interval)

	ticker := time.NewTicker(gc.interval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			gc.run(ctx)
		case <-gc.stopCh:
			klog.InfoS("Stopping garbage collector")
			return
		case <-ctx.Done():
			klog.InfoS("Garbage collector context done")
			return
		}
	}
}

func (gc *GarbageCollector) Stop() {
	close(gc.stopCh)
}

func (gc *GarbageCollector) run(ctx context.Context) {
	klog.V(4).InfoS("Running garbage collection")

	gc.cleanupExpiredSandboxes(ctx)
	gc.cleanupInactiveSandboxes(ctx)
}

func (gc *GarbageCollector) cleanupExpiredSandboxes(ctx context.Context) {
	sandboxes, err := gc.k8sClient.ListExpiredSandboxes(ctx, time.Now())
	if err != nil {
		klog.ErrorS(err, "Failed to list expired sandboxes")
		return
	}

	for _, sandbox := range sandboxes {
		name := sandbox["metadata"].(map[string]interface{})["name"].(string)
		namespace := sandbox["metadata"].(map[string]interface{})["namespace"].(string)

		if err := gc.k8sClient.DeleteSandbox(ctx, namespace, name); err != nil {
			klog.ErrorS(err, "Failed to delete expired sandbox", "namespace", namespace, "name", name)
			continue
		}

		klog.InfoS("Deleted expired sandbox", "namespace", namespace, "name", name)
	}
}

func (gc *GarbageCollector) cleanupInactiveSandboxes(ctx context.Context) {
	sandboxes, err := gc.k8sClient.ListExpiredSandboxes(ctx, time.Now())
	if err != nil {
		klog.ErrorS(err, "Failed to list inactive sandboxes")
		return
	}

	for _, sandbox := range sandboxes {
		annotations, ok := sandbox["metadata"].(map[string]interface{})["annotations"].(map[string]interface{})
		if !ok {
			continue
		}

		lastActivityStr, ok := annotations[LastActivityAnnotationKey].(string)
		if !ok {
			continue
		}

		lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
		if err != nil {
			continue
		}

		idleTimeoutStr, ok := annotations[IdleTimeoutAnnotationKey].(string)
		if !ok {
			idleTimeoutStr = DefaultSandboxIdleTimeout.String()
		}

		idleTimeout, err := time.ParseDuration(idleTimeoutStr)
		if err != nil {
			idleTimeout = DefaultSandboxIdleTimeout
		}

		if time.Since(lastActivity) > idleTimeout {
			name := sandbox["metadata"].(map[string]interface{})["name"].(string)
			namespace := sandbox["metadata"].(map[string]interface{})["namespace"].(string)

			if err := gc.k8sClient.DeleteSandbox(ctx, namespace, name); err != nil {
				klog.ErrorS(err, "Failed to delete inactive sandbox", "namespace", namespace, "name", name)
				continue
			}

			klog.InfoS("Deleted inactive sandbox", "namespace", namespace, "name", name)
		}
	}
}

