func (gc *GarbageCollector) cleanupExpiredSandboxes(ctx context.Context) {
	sandboxes, err := gc.k8sClient.ListExpiredSandboxes(ctx, time.Now())
	if err != nil {
		klog.ErrorS(err, "Failed to list expired sandboxes")
		return
	}

	for _, sandbox := range sandboxes {
		name := sandbox.GetName()
		namespace := sandbox.GetNamespace()

		if err := gc.k8sClient.DeleteSandbox(ctx, namespace, name); err != nil {
