package workloadmanager

import (
	"context"
	"fmt"
	"time"

	"github.com/google/uuid"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/apis/meta/v1/unstructured"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

func (s *Server) buildSandboxForAgentRuntime(ctx context.Context, req *types.CreateSandboxRequest, sessionID string) (*types.SandboxInfo, error) {
	agentRuntime, err := s.k8sClient.GetAgentRuntime(ctx, req.Namespace, req.Name)
	if err != nil {
		klog.ErrorS(err, "Failed to get AgentRuntime", "name", req.Name, "namespace", req.Namespace)
		return nil, api.NewSandboxTemplateNotFoundError(req.Namespace, req.Name, types.AgentRuntimeKind)
	}

	sandboxName := generateSandboxName(sessionID)
	sandbox := buildSandboxObject(sandboxName, req.Namespace, sessionID, req.Name, types.AgentRuntimeKind)

	template, ok := agentRuntime["spec"].(map[string]interface{})["podTemplate"].(map[string]interface{})
	if !ok {
		return nil, api.ErrTemplateMissing
	}

	if err := applyTemplateToSandbox(sandbox, template); err != nil {
		return nil, fmt.Errorf("failed to apply template: %w", err)
	}

	labels := sandbox.GetLabels()
	if labels == nil {
		labels = make(map[string]string)
	}
	labels[SessionIdLabelKey] = sessionID
	labels[WorkloadNameLabelKey] = req.Name
	labels[WorkloadNamespaceLabelKey] = req.Namespace
	labels[WorkloadKindLabelKey] = types.AgentRuntimeKind
	sandbox.SetLabels(labels)

	annotations := sandbox.GetAnnotations()
	if annotations == nil {
		annotations = make(map[string]string)
	}
	now := time.Now().Format(time.RFC3339)
	annotations[LastActivityAnnotationKey] = now

	sessionTimeout := DefaultSandboxIdleTimeout
	if timeout, ok := agentRuntime["spec"].(map[string]interface{})["sessionTimeout"].(string); ok && timeout != "" {
		if d, err := time.ParseDuration(timeout); err == nil {
			sessionTimeout = d
		}
	}
	annotations[IdleTimeoutAnnotationKey] = sessionTimeout.String()

	expiresAt := time.Now().Add(DefaultSandboxTTL)
	annotations[ExpiresAtAnnotationKey] = expiresAt.Format(time.RFC3339)
	sandbox.SetAnnotations(annotations)

	created, err := s.k8sClient.CreateSandbox(ctx, req.Namespace, sandbox.Object)
	if err != nil {
		return nil, fmt.Errorf("failed to create sandbox: %w", err)
	}

	klog.InfoS("Created sandbox for AgentRuntime", "sandbox", sandboxName, "sessionID", sessionID)

	sandboxID := ""
	if uid, ok := created["metadata"].(map[string]interface{})["uid"].(string); ok {
		sandboxID = uid
	}

	entryPoints := extractEntryPoints(agentRuntime)

	return &types.SandboxInfo{
		Kind:             types.AgentRuntimeKind,
		SandboxID:        sandboxID,
		SandboxNamespace: req.Namespace,
		Name:             sandboxName,
		EntryPoints:      entryPoints,
		SessionID:        sessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        expiresAt,
		Status:           "Pending",
	}, nil
}

func (s *Server) buildSandboxForCodeInterpreter(ctx context.Context, req *types.CreateSandboxRequest, sessionID string) (*types.SandboxInfo, error) {
	codeInterpreter, err := s.k8sClient.GetCodeInterpreter(ctx, req.Namespace, req.Name)
	if err != nil {
		klog.ErrorS(err, "Failed to get CodeInterpreter", "name", req.Name, "namespace", req.Namespace)
		return nil, api.NewSandboxTemplateNotFoundError(req.Namespace, req.Name, types.CodeInterpreterKind)
	}

	sandboxName := generateSandboxName(sessionID)
	sandbox := buildSandboxObject(sandboxName, req.Namespace, sessionID, req.Name, types.CodeInterpreterKind)

	template, ok := codeInterpreter["spec"].(map[string]interface{})["template"].(map[string]interface{})
	if !ok {
		return nil, api.ErrTemplateMissing
	}

	if err := applyCodeInterpreterTemplate(sandbox, template); err != nil {
		return nil, fmt.Errorf("failed to apply template: %w", err)
	}

	labels := sandbox.GetLabels()
	if labels == nil {
		labels = make(map[string]string)
	}
	labels[SessionIdLabelKey] = sessionID
	labels[WorkloadNameLabelKey] = req.Name
	labels[WorkloadNamespaceLabelKey] = req.Namespace
	labels[WorkloadKindLabelKey] = types.CodeInterpreterKind
	sandbox.SetLabels(labels)

	annotations := sandbox.GetAnnotations()
	if annotations == nil {
		annotations = make(map[string]string)
	}
	now := time.Now().Format(time.RFC3339)
	annotations[LastActivityAnnotationKey] = now

	sessionTimeout := DefaultSandboxIdleTimeout
	if timeout, ok := codeInterpreter["spec"].(map[string]interface{})["sessionTimeout"].(string); ok && timeout != "" {
		if d, err := time.ParseDuration(timeout); err == nil {
			sessionTimeout = d
		}
	}
	annotations[IdleTimeoutAnnotationKey] = sessionTimeout.String()

	expiresAt := time.Now().Add(DefaultSandboxTTL)
	annotations[ExpiresAtAnnotationKey] = expiresAt.Format(time.RFC3339)
	sandbox.SetAnnotations(annotations)

	created, err := s.k8sClient.CreateSandbox(ctx, req.Namespace, sandbox.Object)
	if err != nil {
		return nil, fmt.Errorf("failed to create sandbox: %w", err)
	}

	klog.InfoS("Created sandbox for CodeInterpreter", "sandbox", sandboxName, "sessionID", sessionID)

	sandboxID := ""
	if uid, ok := created["metadata"].(map[string]interface{})["uid"].(string); ok {
		sandboxID = uid
	}

	entryPoints := extractCodeInterpreterEntryPoints(codeInterpreter)

	return &types.SandboxInfo{
		Kind:             types.CodeInterpreterKind,
		SandboxID:        sandboxID,
		SandboxNamespace: req.Namespace,
		Name:             sandboxName,
		EntryPoints:      entryPoints,
		SessionID:        sessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        expiresAt,
		Status:           "Pending",
	}, nil
}

func generateSandboxName(sessionID string) string {
	return "sandbox-" + sessionID[:8]
}

func buildSandboxObject(name, namespace, sessionID, workloadName, workloadKind string) *unstructured.Unstructured {
	return &unstructured.Unstructured{
		Object: map[string]interface{}{
			"apiVersion": "agents.x-k8s.io/v1alpha1",
			"kind":       "Sandbox",
			"metadata": map[string]interface{}{
				"name":      name,
				"namespace": namespace,
				"labels": map[string]interface{}{
					SessionIdLabelKey:         sessionID,
					WorkloadNameLabelKey:      workloadName,
					WorkloadNamespaceLabelKey: namespace,
					WorkloadKindLabelKey:      workloadKind,
				},
			},
			"spec": map[string]interface{}{
				"template": map[string]interface{}{
					"spec": map[string]interface{}{
						"containers": []interface{}{},
					},
				},
			},
		},
	}
}

func applyTemplateToSandbox(sandbox *unstructured.Unstructured, template map[string]interface{}) error {
	spec, ok := template["spec"].(map[string]interface{})
	if !ok {
		return fmt.Errorf("template missing spec")
	}

	sandboxSpec, ok := sandbox.Object["spec"].(map[string]interface{})
	if !ok {
		sandboxSpec = make(map[string]interface{})
		sandbox.Object["spec"] = sandboxSpec
	}

	sandboxSpec["template"] = map[string]interface{}{
		"spec": spec,
	}

	if labels, ok := template["labels"].(map[string]interface{}); ok {
		sandboxLabels := sandbox.GetLabels()
		if sandboxLabels == nil {
			sandboxLabels = make(map[string]string)
		}
		for k, v := range labels {
			if vs, ok := v.(string); ok {
				sandboxLabels[k] = vs
			}
		}
		sandbox.SetLabels(sandboxLabels)
	}

	if annotations, ok := template["annotations"].(map[string]interface{}); ok {
		sandboxAnnotations := sandbox.GetAnnotations()
		if sandboxAnnotations == nil {
			sandboxAnnotations = make(map[string]string)
		}
		for k, v := range annotations {
			if vs, ok := v.(string); ok {
				sandboxAnnotations[k] = vs
			}
		}
		sandbox.SetAnnotations(sandboxAnnotations)
	}

	return nil
}

func applyCodeInterpreterTemplate(sandbox *unstructured.Unstructured, template map[string]interface{}) error {
	sandboxSpec, ok := sandbox.Object["spec"].(map[string]interface{})
	if !ok {
		sandboxSpec = make(map[string]interface{})
		sandbox.Object["spec"] = sandboxSpec
	}

	podSpec := map[string]interface{}{
		"containers": []interface{}{
			map[string]interface{}{
				"name":  "main",
				"image": template["image"],
			},
		},
	}

	if image, ok := template["image"].(string); ok {
		podSpec["containers"].([]interface{})[0].(map[string]interface{})["image"] = image
	}

	if command, ok := template["command"].([]interface{}); ok {
		podSpec["containers"].([]interface{})[0].(map[string]interface{})["command"] = command
	}

	if args, ok := template["args"].([]interface{}); ok {
		podSpec["containers"].([]interface{})[0].(map[string]interface{})["args"] = args
	}

	if env, ok := template["environment"].([]interface{}); ok {
		podSpec["containers"].([]interface{})[0].(map[string]interface{})["env"] = env
	}

	if resources, ok := template["resources"].(map[string]interface{}); ok {
		podSpec["containers"].([]interface{})[0].(map[string]interface{})["resources"] = resources
	}

	sandboxSpec["template"] = map[string]interface{}{
		"spec": podSpec,
	}

	if labels, ok := template["labels"].(map[string]interface{}); ok {
		sandboxLabels := sandbox.GetLabels()
		if sandboxLabels == nil {
			sandboxLabels = make(map[string]string)
		}
